import * as React from "react";

import SearchIcon from "../icons/SearchIcon";
import { cn } from "../utils/cn";

type ExpandableSearchProps = {
  /** Current search value. */
  value?: string;
  /** Called when the input value changes. */
  onChange?: (value: string) => void;
  /** Placeholder text shown when expanded. */
  placeholder?: string;
  className?: string;
};

/**
 * A collapsible search input matching the Vue V2 Search filter pattern.
 *
 * Renders as a compact 45px-wide icon button by default. On focus (or click),
 * it expands to 300px revealing the text input. When blurred and empty, it
 * collapses back to the icon-only state.
 *
 * The expand/collapse transition uses `width 0.2s ease-in-out` matching the
 * Vue CSS transition.
 */
function ExpandableSearch({
  value = "",
  onChange,
  placeholder = "Search...",
  className,
}: ExpandableSearchProps) {
  const [expanded, setExpanded] = React.useState(false);
  const inputRef = React.useRef<HTMLInputElement>(null);

  const isActive = expanded || value.length > 0;

  function handleFocus() {
    setExpanded(true);
  }

  function handleBlur() {
    if (!value || value.length === 0) {
      setExpanded(false);
    }
  }

  function handleClick() {
    setExpanded(true);
    inputRef.current?.focus();
  }

  return (
    <div
      data-slot="expandable-search"
      className={cn(
        "relative inline-flex h-[44px] items-center overflow-hidden rounded border border-brand-grey-400 bg-white",
        className,
      )}
      style={{
        width: isActive ? 300 : 45,
        transition: "width 0.2s ease-in-out",
      }}
    >
      <button
        type="button"
        className="flex h-full w-[45px] shrink-0 items-center justify-center text-muted-foreground"
        onClick={handleClick}
        tabIndex={-1}
        aria-label="Search"
      >
        <SearchIcon size="sm" />
      </button>
      <input
        ref={inputRef}
        type="text"
        data-slot="expandable-search-input"
        className="h-full w-full min-w-0 border-none bg-transparent pr-3 text-sm outline-none placeholder:text-muted-foreground"
        value={value}
        onChange={(e) => onChange?.(e.target.value)}
        onFocus={handleFocus}
        onBlur={handleBlur}
        placeholder={placeholder}
      />
    </div>
  );
}

export { ExpandableSearch };
export type { ExpandableSearchProps };
